"use client"
import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"
import { motion, HTMLMotionProps } from "framer-motion"
import { cn } from "../../lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-[var(--foreground)] disabled:pointer-events-none disabled:opacity-50 font-ui",
  {
    variants: {
      variant: {
        default:
          "bg-brand-solar text-[var(--command-black)] shadow hover:bg-[var(--solar-hover)]",
        destructive:
          "bg-[var(--error)] text-white shadow-sm hover:bg-[var(--error)]/90",
        outline:
          "border border-surface-border bg-transparent shadow-sm hover:bg-surface-hover hover:text-[var(--foreground)]",
        secondary:
          "bg-surface-hover text-[var(--foreground)] shadow-sm hover:bg-surface-hover/80",
        ghost: "hover:bg-surface-hover hover:text-[var(--foreground)]",
        link: "text-brand-solar underline-offset-4 hover:underline",
        glow: "bg-surface-main text-brand-solar border border-brand-solar/50 shadow-[var(--shadow-glow)] hover:bg-brand-solar/10 hover:border-brand-solar transition-all duration-300",
      },
      size: {
        default: "h-9 px-4 py-2",
        sm: "h-8 rounded-md px-3 text-xs",
        lg: "h-10 rounded-md px-8",
        icon: "h-9 w-9",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean
  withMotion?: boolean
}

// Since Framer motion props conflict with standard HTML props in complex intersections,
// we define a clean union type if we want standard + motion behaviors.
type MotionButtonProps = ButtonProps & Omit<HTMLMotionProps<"button">, keyof ButtonProps>

const Button = React.forwardRef<HTMLButtonElement, MotionButtonProps>(
  ({ className, variant, size, asChild = false, withMotion = false, ...props }, ref) => {
    // If asChild is used (usually with Radix), we can't easily wrap with framer-motion directly 
    // unless we use motion.create(Slot). Keep it simple here for the base component.
    const Comp = asChild ? Slot : "button"
    
    // We only enable frame motion if explicitly requested or if it's the "glow" variant 
    // (a luxury brand touch). 
    if (withMotion || variant === "glow") {
      const MotionComp = motion.create(Comp as any)
      return (
        <MotionComp
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
          className={cn(buttonVariants({ variant, size, className }))}
          ref={ref as any}
          {...(props as any)}
        />
      )
    }

    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    )
  }
)
Button.displayName = "Button"

export { Button, buttonVariants }
